import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/api';

const GuardDashboard = () => {
  const navigate = useNavigate();
  const [attendanceLog, setAttendanceLog] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
      return;
    }

    fetchAttendance();
  }, [navigate]);

  const fetchAttendance = async () => {
    try {
      const res = await API.get('/api/attendance/logs');
      setAttendanceLog(res.data);
      setLoading(false);
    } catch (err) {
      console.log('Error fetching attendance:', err);
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    navigate('/');
  };

  return (
    <div className="container py-5">
      <div className="row mb-4">
        <div className="col-md-8">
          <h1>🛡️ Guard Dashboard</h1>
          <p className="text-muted">Monitor and record student entry</p>
        </div>
        <div className="col-md-4 text-end">
          <button className="btn btn-danger" onClick={handleLogout}>Logout</button>
        </div>
      </div>

      <div className="row">
        <div className="col-md-6 mb-3">
          <div className="card">
            <div className="card-body text-center">
              <h3>📷</h3>
              <h5>Scan QR Code</h5>
              <p className="text-muted">Verify student entry</p>
              <button
                className="btn btn-primary"
                onClick={() => navigate('/guard-scan')}
              >
                Open Scanner
              </button>
            </div>
          </div>
        </div>

        <div className="col-md-6 mb-3">
          <div className="card">
            <div className="card-body text-center">
              <h3>📊</h3>
              <h5>Today's Records</h5>
              <p className="text-muted">View entry logs</p>
              <p className="display-6 text-primary">{attendanceLog.length}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="card mt-4">
        <div className="card-header">
          <h5>📋 Entry Log</h5>
        </div>
        <div className="card-body">
          {loading ? (
            <p>Loading...</p>
          ) : attendanceLog.length > 0 ? (
            <table className="table table-striped">
              <thead>
                <tr>
                  <th>Student Name</th>
                  <th>Roll Number</th>
                  <th>Entry Time</th>
                  <th>Date</th>
                </tr>
              </thead>
              <tbody>
                {attendanceLog.map((log) => (
                  <tr key={log._id}>
                    <td>{log.studentId?.name || 'N/A'}</td>
                    <td>{log.studentId?.roll || 'N/A'}</td>
                    <td>{log.time}</td>
                    <td>{log.date}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <p className="text-muted">No attendance records yet today.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default GuardDashboard;
