import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/api';

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('students');
  const [students, setStudents] = useState([]);
  const [guards, setGuards] = useState([]);
  const [lateLogs, setLateLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
      return;
    }

    fetchData();
  }, [navigate]);

  const fetchData = async () => {
    try {
      // Fetch all registered users
      const usersRes = await API.get('/api/auth/check-users');
      const allUsers = usersRes.data;

      setStudents(allUsers.filter(u => u.role === 'student'));
      setGuards(allUsers.filter(u => u.role === 'guard'));

      // Fetch all late logs
      const logsRes = await API.get('/api/attendance/all-logs');
      setLateLogs(logsRes.data);

      setLoading(false);
    } catch (err) {
      console.log('Error fetching data:', err);
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    navigate('/');
  };

  const deleteUser = async (userId) => {
    if (window.confirm('Are you sure you want to delete this user?')) {
      try {
        await API.delete(`/api/auth/user/${userId}`);
        alert('User deleted successfully');
        fetchData();
      } catch (err) {
        alert('Error deleting user');
      }
    }
  };

  return (
    <div className="container py-5">
      <div className="row mb-4">
        <div className="col-md-8">
          <h1>🔑 Admin Dashboard</h1>
          <p className="text-muted">Manage users and attendance records</p>
        </div>
        <div className="col-md-4 text-end">
          <button className="btn btn-danger" onClick={handleLogout}>Logout</button>
        </div>
      </div>

      {/* Tabs */}
      <nav className="nav nav-tabs mb-4">
        <button
          className={`nav-link ${activeTab === 'students' ? 'active' : ''}`}
          onClick={() => setActiveTab('students')}
        >
          🎓 Students
        </button>
        <button
          className={`nav-link ${activeTab === 'guards' ? 'active' : ''}`}
          onClick={() => setActiveTab('guards')}
        >
          👮 Guards
        </button>
        <button
          className={`nav-link ${activeTab === 'logs' ? 'active' : ''}`}
          onClick={() => setActiveTab('logs')}
        >
          ⚠️ Late Logs
        </button>
      </nav>

      {/* Tab Contents */}
      {loading ? (
        <p>Loading...</p>
      ) : (
        <>
          {activeTab === 'students' && (
            <div className="card">
              <div className="card-header">
                <h5>Registered Students ({students.length})</h5>
              </div>
              <div className="card-body table-responsive">
                {students.length > 0 ? (
                  <table className="table table-striped">
                    <thead>
                      <tr>
                        <th>Name</th>
                        <th>Roll Number</th>
                        <th>Phone</th>
                        <th>Role</th>
                        <th>Action</th>
                      </tr>
                    </thead>
                    <tbody>
                      {students.map((student) => (
                        <tr key={student._id}>
                          <td>{student.name}</td>
                          <td>{student.roll}</td>
                          <td>N/A</td>
                          <td><span className="badge bg-info">Student</span></td>
                          <td>
                            <button
                              className="btn btn-sm btn-danger"
                              onClick={() => deleteUser(student._id)}
                            >
                              Delete
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                ) : (
                  <p className="text-muted">No students registered yet.</p>
                )}
              </div>
            </div>
          )}

          {activeTab === 'guards' && (
            <div className="card">
              <div className="card-header">
                <h5>Registered Guards ({guards.length})</h5>
              </div>
              <div className="card-body table-responsive">
                {guards.length > 0 ? (
                  <table className="table table-striped">
                    <thead>
                      <tr>
                        <th>Name</th>
                        <th>Phone</th>
                        <th>Role</th>
                        <th>Action</th>
                      </tr>
                    </thead>
                    <tbody>
                      {guards.map((guard) => (
                        <tr key={guard._id}>
                          <td>{guard.name}</td>
                          <td>N/A</td>
                          <td><span className="badge bg-warning">Guard</span></td>
                          <td>
                            <button
                              className="btn btn-sm btn-danger"
                              onClick={() => deleteUser(guard._id)}
                            >
                              Delete
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                ) : (
                  <p className="text-muted">No guards registered yet.</p>
                )}
              </div>
            </div>
          )}

          {activeTab === 'logs' && (
            <div className="card">
              <div className="card-header">
                <h5>Late Entry Logs ({lateLogs.length})</h5>
              </div>
              <div className="card-body table-responsive">
                {lateLogs.length > 0 ? (
                  <table className="table table-striped">
                    <thead>
                      <tr>
                        <th>Student Name</th>
                        <th>Date</th>
                        <th>Time</th>
                        <th>QR Data</th>
                      </tr>
                    </thead>
                    <tbody>
                      {lateLogs.map((log) => (
                        <tr key={log._id}>
                          <td>Loading...</td>
                          <td>{log.date}</td>
                          <td>{log.time}</td>
                          <td className="text-muted small">{log.qrData?.substring(0, 20)}...</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                ) : (
                  <p className="text-muted">No late entry logs yet.</p>
                )}
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default AdminDashboard;
