import React, { useEffect, useState, useRef } from 'react';
import QRCode from 'qrcode';
import { useNavigate } from 'react-router-dom';

const ScanQR = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [timeLeft, setTimeLeft] = useState(60);
  const qrRef = useRef(null);
  const timerRef = useRef(null);
  const userRef = useRef(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    const user = localStorage.getItem('user');
    
    if (!token || !user) {
      navigate('/login');
      return;
    }

    userRef.current = JSON.parse(user);
    generateQR();
    setLoading(false);

    // Timer for countdown
    timerRef.current = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          generateQR();
          return 60;
        }
        return prev - 1;
      });
    }, 1000);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [navigate]);

  const generateQR = () => {
    if (!userRef.current) return;
    
    const qrData = `CAMPUS_${userRef.current.roll}_${userRef.current.name}_${Date.now()}`;
    setTimeLeft(60);

    if (qrRef.current) {
      qrRef.current.innerHTML = '';
      
      // Create a canvas element
      const canvas = document.createElement('canvas');
      qrRef.current.appendChild(canvas);
      
      QRCode.toCanvas(
        canvas,
        qrData,
        { 
          width: 250, 
          margin: 2, 
          color: { dark: '#000000', light: '#FFFFFF' },
          errorCorrectionLevel: 'H'
        },
        (err) => {
          if (err) console.error('QR Generation Error:', err);
        }
      );
    }
  };

  return (
    <div className="container py-5">
      <div className="card mx-auto" style={{ maxWidth: '500px' }}>
        <div className="card-body text-center">
          <h2 className="card-title mb-4">📱 Your Entry Pass</h2>
          
          {loading ? (
            <div className="spinner-border text-primary" role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          ) : (
            <>
              <p className="text-muted mb-3">Show this QR code to the guard for entry</p>
              
              <div 
                ref={qrRef}
                style={{
                  display: 'flex',
                  justifyContent: 'center',
                  alignItems: 'center',
                  padding: '30px',
                  backgroundColor: '#f8f9fa',
                  borderRadius: '12px',
                  marginBottom: '20px',
                  border: '2px solid #dee2e6'
                }}
              />
              
              <div className="alert alert-info mb-3">
                <strong>🔐 Security Code:</strong> Refreshes in <span className="badge bg-warning text-dark">{timeLeft}s</span>
              </div>
              
              <div className="p-3 bg-light rounded mb-3">
                <p className="mb-1"><small><strong>📋 Name:</strong> {userRef.current?.name}</small></p>
                <p className="mb-1"><small><strong>🆔 Roll:</strong> {userRef.current?.roll}</small></p>
                <p className="mb-0"><small>⏱️ <strong>Valid:</strong> 60 seconds only</small></p>
              </div>
              
              <button 
                className="btn btn-outline-secondary w-100 mb-2"
                onClick={generateQR}
              >
                🔄 Refresh QR Code Now
              </button>
              
              <button 
                className="btn btn-secondary w-100"
                onClick={() => navigate('/dashboard')}
              >
                ← Back to Dashboard
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default ScanQR;
