import React, { useEffect, useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Html5QrcodeScanner } from 'html5-qrcode';
import API from '../api/api';

const GuardScanner = () => {
  const navigate = useNavigate();
  const [scanning, setScanning] = useState(false);
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('');
  const [scannedList, setScannedList] = useState([]);
  const scannerRef = useRef(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) {
      navigate('/login');
      return;
    }

    return () => {
      if (scannerRef.current) {
        try {
          scannerRef.current.clear().catch(e => console.log('Cleanup:', e));
        } catch (e) {
          console.log('Cleanup error:', e);
        }
      }
    };
  }, [navigate]);

  const startScanner = async () => {
    if (scanning) return;
    
    try {
      setScanning(true);
      setMessage('🎥 Starting camera...');
      setMessageType('info');

      // Wait for DOM to be ready
      await new Promise(resolve => setTimeout(resolve, 100));

      // Check if container exists
      const container = document.getElementById('reader');
      if (!container) {
        console.error('Container element with id="reader" not found');
        setMessage('❌ DOM Error: Reader container not found');
        setMessageType('danger');
        setScanning(false);
        return;
      }

      // Clear any existing scanner
      if (scannerRef.current) {
        try {
          await scannerRef.current.clear();
        } catch (e) {
          console.log('Clear error:', e);
        }
      }

      const scanner = new Html5QrcodeScanner(
        'reader',
        {
          fps: 10,
          qrbox: { width: 250, height: 250 },
          useBarCodeDetectorIfSupported: true,
          rememberLastUsedCamera: true
        },
        false
      );

      scannerRef.current = scanner;

      // Render scanner
      await scanner.render(
        (decodedText) => {
          handleQRScanned(decodedText, scanner);
        },
        (errorMessage) => {
          // Scanning errors - continue quietly
          console.log('Scan attempt:', errorMessage);
        }
      );

      setMessage('📷 Camera ready - Point at QR code');
      setMessageType('success');
    } catch (err) {
      console.error('Scanner error:', err);
      setMessage('❌ Camera error: ' + err.message);
      setMessageType('danger');
      setScanning(false);
    }
  };

  const handleQRScanned = async (qrData, scanner) => {
    try {
      // Pause scanner
      await scanner.pause(true);

      // Parse QR: CAMPUS_101_John Doe_1708449721234
      const parts = qrData.split('_');
      
      if (parts[0] !== 'CAMPUS' || parts.length < 3) {
        setMessage('❌ Invalid QR! Scan student QR code.');
        setMessageType('danger');
        setTimeout(() => scanner.resume(), 1500);
        return;
      }

      const roll = parts[1];
      const studentName = parts[2];

      setMessage('⏳ Recording...');
      setMessageType('info');

      // Mark attendance
      const res = await API.post('/api/attendance/mark', { qrData });

      setMessage(`✅ ${studentName} (${roll})`);
      setMessageType('success');

      // Add to list
      setScannedList(prev => [...prev, {
        name: studentName,
        roll: roll,
        time: new Date().toLocaleTimeString('en-IN'),
        date: new Date().toLocaleDateString('en-IN'),
        status: 'Recorded'
      }]);

      // Resume scanning
      setTimeout(() => {
        scanner.resume();
        setMessage('📷 Scan next QR code...');
        setMessageType('info');
      }, 2000);

    } catch (err) {
      const msg = err.response?.data?.message || err.message || 'Error';
      setMessage(`❌ ${msg}`);
      setMessageType('danger');
      setTimeout(() => scanner.resume(), 1500);
    }
  };

  const stopScanner = async () => {
    if (scannerRef.current) {
      try {
        await scannerRef.current.clear();
      } catch (e) {
        console.log('Stop error:', e);
      }
    }
    setScanning(false);
    setMessage('');
  };

  const handleLogout = () => {
    stopScanner();
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/');
  };

  return (
    <div className="container py-5">
      <div className="row mb-4">
        <div className="col-md-8">
          <h1>📷 Guard - Attendance Scanner</h1>
          <p className="text-muted">Scan student QR codes</p>
        </div>
        <div className="col-md-4 text-end">
          <button className="btn btn-secondary me-2" onClick={() => navigate('/guard')}>
            ← Back
          </button>
          <button className="btn btn-danger" onClick={handleLogout}>
            Logout
          </button>
        </div>
      </div>

      <div className="row">
        <div className="col-lg-8">
          <div className="card">
            <div className="card-header bg-primary text-white">
              <h5 className="mb-0">📹 Scanner</h5>
            </div>
            <div className="card-body" style={{ minHeight: '450px' }}>
              {!scanning ? (
                <div className="text-center d-flex flex-column justify-content-center" style={{ minHeight: '400px' }}>
                  <div style={{ fontSize: '5rem' }}>📹</div>
                  <h3 className="mt-3">Ready to Scan</h3>
                  <p className="text-muted">Click button to start camera</p>
                  <button 
                    className="btn btn-lg btn-success mt-3"
                    onClick={startScanner}
                  >
                    🎥 Start Camera
                  </button>
                </div>
              ) : (
                <>
                  <div 
                    id="reader" 
                    style={{ 
                      width: '100%', 
                      height: '400px',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      backgroundColor: '#000'
                    }}
                  ></div>
                  <button 
                    className="btn btn-lg btn-danger w-100 mt-3"
                    onClick={stopScanner}
                  >
                    ⏹️ Stop
                  </button>
                </>
              )}

              {message && (
                <div className={`alert alert-${messageType} mt-3 mb-0`}>
                  {message}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="col-lg-4">
          <div className="card">
            <div className="card-header bg-info text-white">
              <h5 className="mb-0">📊 Scans ({scannedList.length})</h5>
            </div>
            <div className="card-body" style={{ maxHeight: '500px', overflowY: 'auto' }}>
              {scannedList.length > 0 ? (
                <div className="list-group list-group-flush">
                  {scannedList.map((item, i) => (
                    <div key={i} className="list-group-item">
                      <div className="d-flex justify-content-between">
                        <div>
                          <h6 className="mb-1">{item.name}</h6>
                          <small className="text-muted">Roll: {item.roll}</small><br/>
                          <small className="text-success">✓ {item.time}</small>
                        </div>
                        <span className="badge bg-success">Done</span>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-5">
                  <div style={{ fontSize: '2rem' }}>📭</div>
                  <small className="text-muted d-block mt-2">No scans yet</small>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default GuardScanner;
