import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const Dashboard = () => {

  const navigate = useNavigate();
  const [user, setUser] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const userData = localStorage.getItem("user");
    
    if (!token) {
      navigate("/");
    } else if (userData) {
      setUser(JSON.parse(userData));
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/");
  };

  return (
    <div className="container py-5">
      <div className="row mb-4">
        <div className="col-md-8">
          <h1>🎓 Student Dashboard</h1>
          <p className="text-muted">Welcome, {user?.name || 'Student'}!</p>
        </div>
        <div className="col-md-4 text-end">
          <button 
            className="btn btn-danger" 
            onClick={handleLogout}
          >
            Logout
          </button>
        </div>
      </div>

      <div className="row">
        <div className="col-md-6 mb-3">
          <div className="card">
            <div className="card-body text-center">
              <h3>📱</h3>
              <h5>Generate QR Code</h5>
              <p className="text-muted">Get your dynamic entry pass</p>
              <button 
                className="btn btn-primary"
                onClick={() => navigate('/scan')}
              >
                View QR
              </button>
            </div>
          </div>
        </div>

        <div className="col-md-6 mb-3">
          <div className="card">
            <div className="card-body text-center">
              <h3>👤</h3>
              <h5>My Profile</h5>
              <p className="text-muted">View personal information</p>
              <button className="btn btn-secondary">
                {user?.roll || 'View Profile'}
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="card mt-4">
        <div className="card-header">
          <h5>📋 Your Information</h5>
        </div>
        <div className="card-body">
          <table className="table table-borderless">
            <tbody>
              <tr>
                <td><strong>Full Name:</strong></td>
                <td>{user?.name || 'N/A'}</td>
              </tr>
              <tr>
                <td><strong>Roll Number:</strong></td>
                <td>{user?.roll || 'N/A'}</td>
              </tr>
              <tr>
                <td><strong>Account Type:</strong></td>
                <td><span className="badge bg-info">Student</span></td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;